async (page) => {
  const dir = '/Users/tachongrak/claude-artifacts/hr/2026-05-30';
  await page.goto('http://localhost:3000/th/home', { waitUntil: 'domcontentloaded' }).catch(()=>{});
  await page.evaluate(() => {
    let o; try { o = JSON.parse(localStorage.getItem('humi-auth')||'{}'); } catch { o = {}; }
    o.state = o.state || {}; o.state.roles = ['hr_admin','hr_manager'];
    o.state.userId = o.state.userId || 'demo-admin'; o.state.username = o.state.username || 'HR Admin';
    localStorage.setItem('humi-auth', JSON.stringify(o));
  });
  await page.goto('http://localhost:3000/th/admin/employees/emp-004/pay-rate-change', { waitUntil: 'networkidle' }).catch(()=>{});
  await page.waitForTimeout(2000);
  const landed = page.url();
  // which amount-type radio is checked by default?
  const state1 = await page.evaluate(() => {
    const radios = [...document.querySelectorAll('input[type=radio]')].map(r => ({ name: r.getAttribute('name'), val: r.getAttribute('value')||r.getAttribute('aria-label'), checked: r.checked }));
    return radios.filter(r => /percent|flat/i.test(r.val||''));
  });
  // enter a flat THB amount to trigger the auto-% + strikethrough preview
  const amt = page.getByLabelText(/amount value/i).first();
  if (await amt.count()) { await amt.fill('5000').catch(()=>{}); }
  await page.waitForTimeout(800);
  const preview = await page.evaluate(() => {
    const t = document.body.innerText;
    const cur = document.querySelector('[data-testid="salary-preview-current"]');
    return { hasPct: /%/.test(t), curText: cur ? cur.textContent : null };
  });
  await page.screenshot({ path: dir + '/sta83-payrate.png', fullPage: true });
  return JSON.stringify({ landed, defaultRadios: state1, preview });
}

